```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

interface Address { city?: string }
interface User { address?: Address }

export const getCity = (user: User | null | undefined): string =>
  pipe(
    O.fromNullable(user),
    O.chain((u) => O.fromNullable(u.address)),
    O.chain((a) => O.fromNullable(a.city)),
    O.map((c) => c.toUpperCase()),
    O.getOrElse<string>(() => 'UNKNOWN'),
  );
```

`O.fromNullable` lifts each `T | undefined` into `Option<T>`, `O.chain` keeps us in the `Option` world when the next step also returns an `Option`, and `O.getOrElse` collapses the pipeline to a plain `string` at the end.

