```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const parseInt10 = (s: string): O.Option<number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n) ? O.none : O.some(n);
};

const nonZero = (n: number): O.Option<number> =>
  n === 0 ? O.none : O.some(n);

export const reciprocalOf = (input: string): number =>
  pipe(
    parseInt10(input),
    O.chain(nonZero),
    O.map((n) => 1 / n),
    O.getOrElse<number>(() => -1),
  );
```

Both `parseInt10` and `nonZero` return `Option<number>`, so each composes with `O.chain`. The final `O.map` stays on successful values only.

`O.chain` is bind/flatMap for `Option`: if the input is `Some`, it runs your function (which itself returns an `Option`) and keeps the result; if the input is `None`, it short-circuits. `O.map` is the same idea but for plain value-returning functions.

