import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

const nonEmpty = (s: string): E.Either<string, string> =>
  s.trim().length > 0 ? E.right(s) : E.left('email is required');

const hasAt = (s: string): E.Either<string, string> =>
  s.includes('@') ? E.right(s) : E.left("email must contain '@'");

const underMaxLen = (s: string): E.Either<string, string> =>
  s.length < 254 ? E.right(s) : E.left('email must be < 254 chars');

export const validateEmail = (s: string): E.Either<string, string> =>
  pipe(
    nonEmpty(s),
    E.chainW(hasAt),
    E.chainW(underMaxLen),
    E.mapLeft((msg) => `[email] ${msg}`),
  );
```

`E.chainW` is the widening variant — here all the error types happen to be `string`, but using `chainW` keeps the door open to different left types without a manual unification.

```ts
