```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

class TooShort { readonly _tag = 'TooShort' as const }
class TooLong { readonly _tag = 'TooLong' as const }
class BadChars { readonly _tag = 'BadChars' as const }

const lengthOk = (s: string): E.Either<TooShort | TooLong, string> => {
  if (s.length < 3) return E.left(new TooShort());
  if (s.length > 20) return E.left(new TooLong());
  return E.right(s);
};

const alnumOnly = (s: string): E.Either<BadChars, string> =>
  /^[a-zA-Z0-9]+$/.test(s) ? E.right(s) : E.left(new BadChars());

export const normaliseUser = (raw: string): string =>
  pipe(
    lengthOk(raw),
    E.chainW(alnumOnly),
    E.map((s) => s.toLowerCase()),
    E.fold(
      (e) => `invalid:${e._tag}`,
      (u) => `ok:${u}`,
    ),
  );
```

`E.chain` / `E.chainW` is bind for `Either`: on `Right(a)` it runs your function `a -> Either<E', B>` and returns its result; on `Left(e)` it short-circuits. `E.chainW` is the widening form that lets each step have its own error type and unions them in the result.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseErr = 'parse';
type DivZero = 'divzero';

const num = (s: string): E.Either<ParseErr, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left('parse') : E.right(n);
};

const safeDiv = (a: number, b: number): E.Either<DivZero, number> =>
  b === 0 ? E.left('divzero') : E.right(a / b);

export const divide = (
  a: string,
  b: string,
