```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type Malformed = { kind: 'malformed'; part: string };

const splitPair = (part: string): E.Either<Malformed, readonly [string, string]> => {
  const i = part.indexOf('=');
  if (i <= 0) return E.left({ kind: 'malformed', part });
  return E.right([part.slice(0, i), part.slice(i + 1)] as const);
};

const reducePairs = (
  parts: ReadonlyArray<string>,
): E.Either<Malformed, Record<string, string>> =>
  parts.reduce<E.Either<Malformed, Record<string, string>>>(
    (acc, part) =>
      pipe(
        acc,
        E.chain((accMap) =>
          pipe(
            splitPair(part),
            E.map(([k, v]) => ({ ...accMap, [k]: v })),
          ),
        ),
      ),
    E.right({}),
  );

export const parseConfig = (raw: string): E.Either<Malformed, Record<string, string>> =>
  pipe(
    raw.split(';').filter((x) => x.length > 0),
    reducePairs,
  );
```

