import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type DateErr = { _tag: 'InvalidDate' };
type FutureErr = { _tag: 'Future'; iso: string };

const parseIso = (iso: string): E.Either<DateErr, Date> => {
  const d = new Date(iso);
  return Number.isNaN(d.getTime()) ? E.left({ _tag: 'InvalidDate' }) : E.right(d);
};

const notFuture = (now: Date) =>
  (d: Date): E.Either<FutureErr, Date> =>
    d.getTime() <= now.getTime()
      ? E.right(d)
      : E.left({ _tag: 'Future', iso: d.toISOString() });

export const daysAgo = (
  iso: string,
  now: Date,
): E.Either<DateErr | FutureErr, number> =>
  pipe(
    parseIso(iso),
    E.chainW(notFuture(now)),
    E.map((d) => Math.floor((now.getTime() - d.getTime()) / 86_400_000)),
  );
