interface Req { headers: Readonly<Record<string, string | undefined>> }

type Missing = { _tag: 'Missing' };
type BadShape = { _tag: 'BadShape' };
type NotFound = { _tag: 'NotFound'; token: string };

const readHeader = (req: Req): E.Either<Missing, string> => {
  const h = req.headers.authorization;
  return h === undefined ? E.left({ _tag: 'Missing' }) : E.right(h);
};

const takeToken = (h: string): E.Either<BadShape, string> =>
  h.startsWith('Bearer ') ? E.right(h.slice('Bearer '.length)) : E.left({ _tag: 'BadShape' });

const resolveUser = (token: string): E.Either<NotFound, string> =>
  token.length > 0 ? E.right(`user:${token}`) : E.left({ _tag: 'NotFound', token });

export const authUser = (
  req: Req,
): E.Either<Missing | BadShape | NotFound, string> =>
  pipe(readHeader(req), E.chainW(takeToken), E.chainW(resolveUser));
